import React, { useState } from 'react';

// Données fictives pour la démonstration de l'interface (Frontend-only pour le moment)
const MOCK_STOCKS = [
  { id: '1', vaccin: 'COVID-19 (Pfizer)', lot: 'LOT-2024-001', quantiteInitiale: 500, quantiteRestante: 320, datePeremption: '2025-06-30' },
  { id: '2', vaccin: 'COVID-19 (AstraZeneca)', lot: 'LOT-2024-045', quantiteInitiale: 200, quantiteRestante: 15, datePeremption: '2024-08-15' },
  { id: '3', vaccin: 'Grippe (Influvac)', lot: 'LOT-2024-FLU-12', quantiteInitiale: 1000, quantiteRestante: 0, datePeremption: '2024-03-01' },
  { id: '4', vaccin: 'BCG (Tuberculose)', lot: 'LOT-2023-BCG-9', quantiteInitiale: 100, quantiteRestante: 85, datePeremption: '2026-12-01' },
  { id: '5', vaccin: 'ROR', lot: 'LOT-2024-ROR-05', quantiteInitiale: 300, quantiteRestante: 40, datePeremption: '2024-05-10' },
];

export default function Pharmacy() {
  const [stocks, setStocks] = useState(MOCK_STOCKS);
  const [search, setSearch] = useState('');

  // Filtering
  const filteredStocks = stocks.filter(s => 
    s.vaccin.toLowerCase().includes(search.toLowerCase()) || 
    s.lot.toLowerCase().includes(search.toLowerCase())
  );

  // Status calculation helpers
  const getExpirationStatus = (dateString) => {
    const now = new Date();
    const expiryDate = new Date(dateString);
    const diffDays = Math.ceil((expiryDate - now) / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return { label: 'Périmé', color: '#ef4444', bg: '#fee2e2' };
    if (diffDays <= 90) return { label: `Expire dans ${diffDays} j`, color: '#f59e0b', bg: '#fffbeb' };
    return { label: 'Valide', color: '#10b981', bg: '#d1fae5' };
  };

  const getStockStatus = (restante, initiale) => {
    const ratio = restante / initiale;
    if (restante === 0) return { label: 'Rupture', color: '#ef4444' };
    if (ratio <= 0.2) return { label: 'Critique', color: '#f59e0b' };
    return { label: 'Normal', color: '#10b981' };
  };

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '32px' }}>
        <div>
          <h1 style={{ fontFamily: 'Syne', fontSize: 26, fontWeight: 800, color: '#1d2129', marginBottom: 4 }}>Pharmacie & Stocks</h1>
          <p style={{ color: '#8a94a6', fontSize: 14 }}>Gérez l'inventaire des doses, les numéros de lots et les dates d'expiration.</p>
        </div>
        <button style={{ background: '#0056ff', color: 'white', border: 'none', padding: '12px 24px', borderRadius: '50px', fontWeight: 700, display: 'flex', alignItems: 'center', gap: 8, cursor: 'pointer', boxShadow: '0 4px 15px rgba(0,86,255,0.2)' }}>
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"></path><polyline points="3.27 6.96 12 12.01 20.73 6.96"></polyline><line x1="12" y1="22.08" x2="12" y2="12"></line></svg>
          Réceptionner un Lot
        </button>
      </div>

      {/* STATS RAPIDES */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 16, marginBottom: 24 }}>
        <div style={{ background: 'white', padding: 20, borderRadius: 16, border: '1px solid #eaebef', display: 'flex', alignItems: 'center', gap: 16 }}>
          <div style={{ background: '#ebf2ff', color: '#0056ff', width: 48, height: 48, borderRadius: 12, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"></path></svg>
          </div>
          <div>
            <div style={{ fontSize: 13, color: '#8a94a6', fontWeight: 600, textTransform: 'uppercase' }}>Lots Actifs</div>
            <div style={{ fontSize: 24, fontWeight: 800, color: '#1d2129' }}>{stocks.filter(s => s.quantiteRestante > 0).length}</div>
          </div>
        </div>

        <div style={{ background: 'white', padding: 20, borderRadius: 16, border: '1px solid #eaebef', display: 'flex', alignItems: 'center', gap: 16 }}>
          <div style={{ background: '#fff5eb', color: '#f59e0b', width: 48, height: 48, borderRadius: 12, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"></path><line x1="12" y1="9" x2="12" y2="13"></line><line x1="12" y1="17" x2="12.01" y2="17"></line></svg>
          </div>
          <div>
            <div style={{ fontSize: 13, color: '#8a94a6', fontWeight: 600, textTransform: 'uppercase' }}>Stocks Critiques</div>
            <div style={{ fontSize: 24, fontWeight: 800, color: '#1d2129' }}>{stocks.filter(s => s.quantiteRestante > 0 && (s.quantiteRestante/s.quantiteInitiale) <= 0.2).length}</div>
          </div>
        </div>

        <div style={{ background: 'white', padding: 20, borderRadius: 16, border: '1px solid #eaebef', display: 'flex', alignItems: 'center', gap: 16 }}>
          <div style={{ background: '#fee2e2', color: '#ef4444', width: 48, height: 48, borderRadius: 12, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"></rect><line x1="16" y1="2" x2="16" y2="6"></line><line x1="8" y1="2" x2="8" y2="6"></line><line x1="3" y1="10" x2="21" y2="10"></line><line x1="9" y1="15" x2="15" y2="15"></line></svg>
          </div>
          <div>
            <div style={{ fontSize: 13, color: '#8a94a6', fontWeight: 600, textTransform: 'uppercase' }}>Périmés / Ruptures</div>
            <div style={{ fontSize: 24, fontWeight: 800, color: '#1d2129' }}>{stocks.filter(s => s.quantiteRestante === 0 || getExpirationStatus(s.datePeremption).label === 'Périmé').length}</div>
          </div>
        </div>
      </div>

      <div className="card" style={{ border: 'none', padding: '24px', boxShadow: '0 2px 10px rgba(0,0,0,0.02)' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
          <h3 style={{ fontFamily: 'Syne', fontWeight: 800, fontSize: 18 }}>Inventaire des Lots</h3>
          <div style={{ position: 'relative', width: '350px' }}>
            <svg style={{ position: 'absolute', left: 16, top: 10, color: '#8a94a6' }} width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
            <input 
              type="text" 
              placeholder="Rechercher un vaccin ou un numéro de lot..." 
              value={search}
              onChange={e => setSearch(e.target.value)}
              style={{ padding: '10px 16px 10px 42px', borderRadius: '50px', border: '1px solid #eaebef', background: '#f4f5f9', outline: 'none', fontSize: 13, width: '100%', color: '#1d2129' }} 
            />
          </div>
        </div>

        <div style={{ overflowX: 'auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
            <thead>
              <tr style={{ color: '#8a94a6', borderBottom: '1px solid #eaebef' }}>
                <th style={{ padding: '16px 8px', fontWeight: 600, fontSize: 12, textTransform: 'uppercase' }}>Produit Vaccinal</th>
                <th style={{ padding: '16px 8px', fontWeight: 600, fontSize: 12, textTransform: 'uppercase' }}>Numéro de Lot</th>
                <th style={{ padding: '16px 8px', fontWeight: 600, fontSize: 12, textTransform: 'uppercase' }}>Jauge de Stock</th>
                <th style={{ padding: '16px 8px', fontWeight: 600, fontSize: 12, textTransform: 'uppercase' }}>Date d'Expiration</th>
                <th style={{ padding: '16px 8px', textAlign: 'right' }}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredStocks.map((s, i) => {
                const stockStatus = getStockStatus(s.quantiteRestante, s.quantiteInitiale);
                const expiryStatus = getExpirationStatus(s.datePeremption);
                const fillRatio = (s.quantiteRestante / s.quantiteInitiale) * 100;

                return (
                  <tr key={s.id} style={{ borderBottom: i < filteredStocks.length-1 ? '1px solid #eaebef' : 'none', opacity: s.quantiteRestante === 0 ? 0.6 : 1 }}>
                    <td style={{ padding: '16px 8px' }}>
                      <div style={{ fontWeight: 800, color: '#1d2129', fontSize: 14 }}>{s.vaccin}</div>
                    </td>

                    <td style={{ padding: '16px 8px' }}>
                      <div style={{ fontFamily: 'monospace', fontWeight: 700, fontSize: 13, color: '#64748b' }}>{s.lot}</div>
                    </td>

                    <td style={{ padding: '16px 8px', minWidth: '200px' }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6, fontSize: 12 }}>
                        <span style={{ fontWeight: 700, color: stockStatus.color }}>{s.quantiteRestante} doses</span>
                        <span style={{ color: '#8a94a6' }}>/ {s.quantiteInitiale}</span>
                      </div>
                      <div style={{ width: '100%', height: 6, background: '#f4f5f9', borderRadius: 3, overflow: 'hidden' }}>
                        <div style={{ width: `${Math.max(0, fillRatio)}%`, height: '100%', background: stockStatus.color, borderRadius: 3 }}></div>
                      </div>
                    </td>

                    <td style={{ padding: '16px 8px' }}>
                      <span style={{ background: expiryStatus.bg, color: expiryStatus.color, padding: '4px 10px', borderRadius: '6px', fontSize: 12, fontWeight: 700 }}>
                        {new Date(s.datePeremption).toLocaleDateString('fr-FR')} • {expiryStatus.label}
                      </span>
                    </td>

                    <td style={{ padding: '16px 8px', textAlign: 'right' }}>
                       <button style={{ background: '#f4f5f9', border: '1px solid #eaebef', borderRadius: '8px', padding: '8px', cursor: 'pointer', color: '#8a94a6' }} title="Modifier le lot">
                         <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 20h9"></path><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"></path></svg>
                       </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>

          {filteredStocks.length === 0 && (
             <div style={{ padding: '40px 0', textAlign: 'center', color: '#8a94a6' }}>
               Aucun lot de vaccin trouvé.
             </div>
          )}
        </div>
      </div>
    </div>
  );
}
